export var array_of_mutants = [
  mutant1, //0
  mutant2,
  mutant3,
  mutant4,
  mutant5,
  mutant6,
  mutant7,
  mutant8,
  mutant9,
  mutant10,
  mutant11, //10
  mutant12,
  mutant13,
  mutant14,
  mutant15,
  mutant16,
  mutant17,
  mutant18,
  mutant19,
  mutant20,
];

var extraWorkNumber = [];
var extraFreeDayNumber = [];
var gameOverNum = [];
var consecutiveFreeDays = [];
var freeLateness = [];
for (var i = 0; i <= array_of_mutants.length; i++) {
  extraWorkNumber[i] = 0;
  extraFreeDayNumber[i] = 0;
  gameOverNum[i] = false;
  consecutiveFreeDays[i] = 0;
  freeLateness[i] = false;
}

export function init() {
  for (var i = 0; i <= array_of_mutants.length; i++) {
    freeLateness[i] = false;
    consecutiveFreeDays[i] = 0;
  }
}

export function Original(extraWork, holidayNumber, gameOver, operation, i) {
  extraWorkNumber[i] = extraWork;
  extraFreeDayNumber[i] = holidayNumber;
  gameOverNum[i] = gameOver;
  if (gameOver)
    return {
      extraWork: extraWorkNumber[i],
      holidayNumber: extraFreeDayNumber[i],
      gameOver: gameOverNum[i],
    };

  if (operation === "add extra work") {
    if (extraWorkNumber[i] === 2) {
      extraFreeDayNumber[i]++;
      extraWorkNumber[i] = 0;
    } else if (extraWorkNumber[i] === 0 && extraFreeDayNumber[i] < 0) {
      extraFreeDayNumber[i]++;
      extraWorkNumber[i] = -2;
    } else extraWorkNumber[i]++;
  }
  if (operation === "spend holiday") {
    if (extraFreeDayNumber[i] > 0) {
      extraFreeDayNumber[i]--;
      consecutiveFreeDays[i]++;
    }
    if (consecutiveFreeDays[i] === 3) {
      freeLateness[i] = true;
    }
  }
  if (operation === "add lateness") {
    consecutiveFreeDays[i] = 0;
    if (!freeLateness[i]) {
      if (extraWorkNumber[i] === 0 && extraFreeDayNumber[i] > 0) {
        extraFreeDayNumber[i]--;
        extraWorkNumber[i] = 2;
      } else if (extraWorkNumber[i] > 0) extraWorkNumber[i]--;
      else if (extraWorkNumber[i] === -2) {
        extraWorkNumber[i] = -1;
        extraFreeDayNumber[i]--;
      } else if (extraWorkNumber[i] === -1) {
        extraFreeDayNumber[i]--;
        extraWorkNumber[i] = 0;
      } else {
        extraWorkNumber[i] = -2;
      }
      if (extraFreeDayNumber[i] === -3) {
        gameOverNum[i] = true;
      }
    }
    freeLateness[i] = false;
  }
  return {
    extraWork: extraWorkNumber[i],
    holidayNumber: extraFreeDayNumber[i],
    gameOver: gameOverNum[i],
    freeLateness: freeLateness[i],
  };
}

